const _start = $('Start').first().json;
const chatId = (_start.tool_input && _start.tool_input.chat_id) ? _start.tool_input.chat_id : _start.chat_id;
const payload = {
  confirmation_message: 'Your cart is empty. Send me what you need and I will add it for you!',
  chat_id: chatId,
};
return [{ json: payload }];

const root = (() => {
  try {
    const start = $('Start').first();
    if (start && start.json) return start.json;
  } catch {}
  if ($json && typeof $json === 'object' && Object.keys($json).length > 0) return $json;
  try {
    const current = $input.first();
    return (current && current.json) ? current.json : {};
  } catch {}
  return {};
})();
const toolInput = (root.tool_input && typeof root.tool_input === 'object') ? root.tool_input : root;
const chatId = String(toolInput.chat_id || '');

const normalizeUnit = (value) => {
  const map = {
    kg: 'kg', kilo: 'kg', kilos: 'kg', kilogram: 'kg', kilograms: 'kg',
    g: 'g', gm: 'g', gram: 'g', grams: 'g',
    l: 'l', lt: 'l', ltr: 'l', litre: 'l', litres: 'l', liter: 'l', liters: 'l',
    ml: 'ml', millilitre: 'ml', millilitres: 'ml', milliliter: 'ml', milliliters: 'ml',
  };
  return map[String(value || '').toLowerCase().trim()] || String(value || '').toLowerCase().trim() || 'pcs';
};
const formatQty = (value) => Number.isInteger(Number(value)) ? String(Number(value)) : String(Number(Number(value).toFixed(3)));
const quantityLabel = (itemName, unit, quantity) => {
  const lower = String(itemName || '').toLowerCase();
  const packMatch = lower.match(/(\d+(?:\.\d+)?)\s*(kg|kilo|kilos|kilogram|kilograms|g|gm|gram|grams|ml|l|lt|ltr|litre|litres|liter|liters|millilitre|millilitres|milliliter|milliliters)\b/i);
  if (/\bloose\b/.test(lower) && packMatch) return normalizeUnit(packMatch[2]);
  if (packMatch) return Number(quantity) === 1 ? 'pack' : 'packs';
  return normalizeUnit(unit) || 'pcs';
};

const items = $input.all().map((row) => row && row.json ? row.json : null).filter((row) => row && row.sku);
if (!items.length) {
  return [{ json: {
    chat_id: chatId,
    customer_ui_state: 'BROWSE_HOME',
    message_type: 'button',
    body_text: 'Your cart is empty right now.\n\nStart shopping from the menu or send items like "2 milk and 1 bread".',
    buttons: [
      { id: 'start_shopping', title: 'Shop Items' },
      { id: 'get_promos', title: 'Offers' },
    ],
  } }];
}

const enablePricing = (() => {
  try { return $('Get Pricing Flag').first().json.enable_pricing !== false; } catch { return true; }
})();

let total = 0;
const lines = [];
for (const item of items) {
  const lineTotal = Number(item.line_total || 0);
  total += lineTotal;
  const priceStr = enablePricing ? ' — ₹' + lineTotal.toFixed(0) : '';
  lines.push('• ' + item.item_name + ' × ' + formatQty(item.quantity) + ' ' + quantityLabel(item.item_name, item.unit, item.quantity) + priceStr);
}

// Fix 5: item count = distinct rows, not sum of quantities
const itemCount = items.length;
const totalStr = enablePricing ? ' · Total: ₹' + total.toFixed(0) : '';

return [{ json: {
  chat_id: chatId,
  customer_ui_state: 'CART_ACTIVE',
  message_type: 'list',
  body_text: '🛒 Your cart\n\n' + lines.join('\n') + '\n\n' + itemCount + ' item' + (itemCount !== 1 ? 's' : '') + totalStr,
  list_sections: [{
    title: 'Cart actions',
    rows: [
      { id: 'checkout', title: 'Checkout', description: 'Review address and place order' },
      { id: 'add_more', title: 'Add more items', description: 'Keep shopping from the store' },
      { id: 'cancel_order', title: 'Clear cart', description: 'Remove pending cart items' },
    ],
  }],
} }];

